// Dedicated /compare page. Extends the existing compare tray (which
// already has a small IQR chart and mini table) with a full-page
// version: bigger chart, more columns, best/worst highlighting, and
// a shareable URL (the compare list lives in localStorage so it
// survives reloads, but each item is still individually linkable).

import { useMemo, useEffect } from "react";
import { useSearchParams, Link, useNavigate } from "react-router-dom";
import { toast } from "sonner";
import { motion } from "framer-motion";
import { GitCompare, X, Copy, TrendingUp, TrendingDown, Minus, Trophy, Skull, AlertTriangle, ChevronLeft } from "lucide-react";
import { useMarket } from "@/lib/MarketContext";
import { useCompare } from "@/lib/useFavorites";
import { fmt, fmtTime } from "@/lib/parseItem";
import { openItem } from "@/components/landing/DetailDrawer";
import ItemName from "@/components/landing/ItemName";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { Reveal } from "@/components/landing/motion";
import BackToTop from "@/components/landing/BackToTop";
import FreshnessPill from "@/components/landing/FreshnessPill";
import { EmptyState } from "@/components/ui/empty-state";
import {
  AlertDialog,
  AlertDialogTrigger,
  AlertDialogContent,
  AlertDialogHeader,
  AlertDialogFooter,
  AlertDialogTitle,
  AlertDialogDescription,
  AlertDialogAction,
  AlertDialogCancel,
} from "@/components/ui/alert-dialog";

const CONF = {
  high: { color: "text-emerald-400", dot: "bg-emerald-400" },
  good: { color: "text-lime-400", dot: "bg-lime-400" },
  fair: { color: "text-amber-400", dot: "bg-amber-400" },
  low: { color: "text-orange-400", dot: "bg-orange-400" },
  unreliable: { color: "text-zinc-500", dot: "bg-zinc-600" },
};

const TREND = {
  up: { Icon: TrendingUp, color: "text-red-400" },
  down: { Icon: TrendingDown, color: "text-emerald-400" },
  stable: { Icon: Minus, color: "text-zinc-500" },
};

export default function ComparePage() {
  const { market, loading } = useMarket();
  const [searchParams, setSearchParams] = useSearchParams();
  const navigate = useNavigate();
  const compare = useCompare();

  // On mount, import compare items from ?items= URL param into localStorage.
  useEffect(() => {
    const urlItems = searchParams.get("items");
    if (!urlItems) return;
    const keys = urlItems.split(",").filter(Boolean);
    if (keys.length === 0) return;
    const CMP_KEY = "castia.compare";
    try {
      const raw = localStorage.getItem(CMP_KEY);
      const existing = raw ? JSON.parse(raw) : [];
      const merged = Array.from(new Set([...existing, ...keys]));
      localStorage.setItem(CMP_KEY, JSON.stringify(merged));
      window.dispatchEvent(new CustomEvent(`castia:${CMP_KEY.replace("castia.", "")}`));
    } catch { /* ignore */ }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Sync compare items back to ?items= in the URL whenever the list changes.
  useEffect(() => {
    if (compare.count === 0) {
      if (searchParams.has("items")) {
        setSearchParams((prev) => { const next = new URLSearchParams(prev); next.delete("items"); return next; }, { replace: true });
      }
      return;
    }
    const serialized = compare.items.join(",");
    if (searchParams.get("items") !== serialized) {
      setSearchParams((prev) => { const next = new URLSearchParams(prev); next.set("items", serialized); return next; }, { replace: true });
    }
  }, [compare.items, compare.count, searchParams, setSearchParams]);

  const items = useMemo(() => {
    if (!market) return [];
    return (market.rows || []).filter((r) => compare.has(r.key));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [market, compare.items, compare.count]);

  const stats = useMemo(() => {
    if (items.length === 0) return null;
    const medians = items.map((r) => r.median).filter((v) => v > 0);
    if (medians.length === 0) return null;
    const min = Math.min(...medians);
    const max = Math.max(...medians);
    const logMin = Math.log10(Math.max(min * 0.7, 1));
    const logMax = Math.log10(max * 1.1);
    const range = Math.max(logMax - logMin, 0.001);
    return { min, max, logMin, logMax, range, toPct: (v) => {
      if (v <= 0) return 0;
      const pct = ((Math.log10(v) - logMin) / range) * 100;
      return Math.max(0, Math.min(100, pct));
    } };
  }, [items]);

  const best = useMemo(() => items.reduce((b, r) => (!b || (r.median > 0 && r.median < b.median)) ? r : b, null), [items]);
  const worst = useMemo(() => items.reduce((w, r) => (!w || r.median > w.median) ? r : w, null), [items]);
  const totalValue = useMemo(() => items.reduce((s, r) => s + (r.median || 0), 0), [items]);

  return (
    <div data-testid="compare-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <Link
              to="/listings"
              data-testid="compare-back"
              className="inline-flex items-center gap-1 text-zinc-500 hover:text-emerald-400 font-mono text-[10px] uppercase tracking-[0.2em] mb-4 transition-colors"
            >
              <ChevronLeft className="w-3 h-3" /> Back to listings
            </Link>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4 inline-flex items-center gap-2">
              <GitCompare className="w-3 h-3" /> / Compare
            </div>
            <h1 className="font-heading text-5xl sm:text-6xl lg:text-7xl tracking-tighter font-black leading-[0.95]">
              <span className="text-emerald-400 tabular">{compare.count}</span> item{compare.count === 1 ? "" : "s"} to compare.
            </h1>
            <p className="mt-6 text-zinc-400 max-w-2xl text-lg">
              Side-by-side median price, IQR spread, and confidence — log scale so the cheap and the rare can sit on the same axis. Add items from the listings using the <span className="kbd">c</span> shortcut or the table-row compare button.
            </p>
            {market?.stats?.lastUpdatedMs > 0 && (
              <div className="mt-4">
                <FreshnessPill ms={market.stats.lastUpdatedMs} prefix="Snapshot" />
              </div>
            )}
          </Reveal>

          {compare.count === 0 && !loading.market && (
            <Reveal>
              <EmptyState
                icon={GitCompare}
                title="Nothing to compare yet"
                description={`Add up to ${compare.max} items to a side-by-side comparison. Use the compare button on any listings row, or press c while a row is selected.`}
                actions={[
                  { label: "Browse listings", to: "/listings" },
                  { label: "Look up item", onClick: () => navigate("/lookup") },
                ]}
              />
            </Reveal>
          )}

          {items.length > 0 && (
            <Reveal delay={0.1}>
              <div className="mt-10 grid grid-cols-2 md:grid-cols-4 gap-px bg-white/10 border border-white/10 rounded-lg overflow-hidden">
                {[
                  { l: "Comparing", v: `${items.length}/${compare.max}` },
                  { l: "Cheapest", v: best && best.median > 0 ? fmt(best.median) : "—", icon: best ? "Trophy" : null },
                  { l: "Priciest", v: worst && items.length > 1 ? fmt(worst.median) : "—", icon: worst && items.length > 1 ? "Skull" : null },
                  { l: "Total est.", v: totalValue > 0 ? fmt(totalValue) : "—" },
                ].map((s) => (
                  <div key={s.l} className="bg-bg-base p-4">
                    <div className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 flex items-center gap-1.5">
                      {s.icon === "Trophy" && <Trophy className="w-3 h-3 text-emerald-400" />}
                      {s.icon === "Skull" && <Skull className="w-3 h-3 text-red-400" />}
                      {s.l}
                    </div>
                    <div className="mt-1 font-heading text-2xl font-black tabular text-white">{s.v}</div>
                  </div>
                ))}
              </div>
            </Reveal>
          )}

          {/* IQR bar chart (log scale) */}
          {items.length > 0 && stats && (
            <Reveal delay={0.15} className="mt-8">
              <div className="border border-white/10 rounded-2xl p-5 sm:p-6 bg-bg-deep overflow-hidden">
                <div className="flex items-center justify-between mb-5 flex-wrap gap-2">
                  <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500">
                    Side-by-side · log scale · IQR whiskers · median dot
                  </div>
                  <div className="font-mono text-[10px] tabular text-zinc-500">
                    <span className="text-emerald-400">{fmt(stats.min)}</span> → <span className="text-emerald-400">{fmt(stats.max)}</span>
                  </div>
                </div>
                <div className="space-y-3">
                  {items.map((r) => {
                    const isBest = best && r.key === best.key && items.length > 1;
                    const isWorst = worst && r.key === worst.key && items.length > 1;
                    return (
                      <motion.div
                        key={r.key}
                        data-testid={`compare-bar-${r.key}`}
                        drag="x"
                        dragConstraints={{ left: 0, right: 0 }}
                        dragElastic={{ left: 0.15, right: 0 }}
                        onDragEnd={(_, info) => {
                          if (info.offset.x < -80) {
                            compare.toggle(r.key);
                            toast("Item removed from compare");
                          }
                        }}
                        whileDrag={{ opacity: 0.6, scale: 0.97 }}
                        className={`grid grid-cols-1 sm:grid-cols-[220px_1fr_120px] gap-3 items-center py-2 rounded-lg px-2 min-w-0 sm:cursor-default ${isBest ? "bg-emerald-500/[0.04]" : isWorst ? "bg-red-500/[0.04]" : ""}`}
                      >
                        <button
                          onClick={() => openItem(searchParams, setSearchParams, r.key)}
                          data-testid={`compare-open-${r.key}`}
                          className="text-left text-sm font-medium text-white hover:text-emerald-400 transition-colors flex items-center gap-2 min-w-0"
                        >
                          {isBest && <Trophy className="w-3.5 h-3.5 text-emerald-400 shrink-0" />}
                          {isWorst && <Skull className="w-3.5 h-3.5 text-red-400 shrink-0" />}
                          <span className="min-w-0 flex-1"><ItemName name={r.name} tier={r.tier} modifiers={r.modifiers} layout="wrap" /></span>
                        </button>
                        <div className="relative h-8">
                          <div className="absolute inset-y-1/2 -translate-y-px left-0 right-0 h-px bg-white/[0.06]"></div>
                          {r.iqrLow > 0 && r.iqrHigh > 0 && r.iqrHigh > r.iqrLow && (
                            <div
                              style={{ left: `${stats.toPct(r.iqrLow)}%`, width: `${stats.toPct(r.iqrHigh) - stats.toPct(r.iqrLow)}%` }}
                              className={`absolute inset-y-1/2 -translate-y-1.5 h-3 rounded-full ${isBest ? "bg-emerald-500/40 border-emerald-400/60" : isWorst ? "bg-red-500/30 border-red-500/40" : "bg-emerald-500/25 border-emerald-500/30"} border`}
                            />
                          )}
                          <div
                            style={{ left: `${stats.toPct(r.median)}%` }}
                            className={`absolute top-1/2 -translate-y-1/2 -translate-x-1/2 w-3.5 h-3.5 rounded-full ring-2 ring-bg-base ${isBest ? "bg-emerald-300 shadow-[0_0_12px_rgba(16,185,129,0.8)]" : isWorst ? "bg-red-300" : "bg-emerald-400 shadow-[0_0_12px_rgba(16,185,129,0.6)]"}`}
                            title={`${fmt(r.median)} median`}
                          />
                        </div>
                        <div className="text-right font-mono text-sm tabular text-white">
                          {fmt(r.median)}
                          <div className="font-mono text-[9px] text-zinc-500 tabular">
                            {fmt(r.iqrLow)}–{fmt(r.iqrHigh)}
                          </div>
                        </div>
                      </motion.div>
                    );
                  })}
                </div>
                <div className="mt-5 pt-3 border-t border-white/5 flex flex-wrap gap-4 font-mono text-[10px] uppercase tracking-wider text-zinc-500">
                  <span className="inline-flex items-center gap-1.5"><span className="w-3 h-3 rounded-full bg-emerald-400 ring-2 ring-bg-base"></span> Median</span>
                  <span className="inline-flex items-center gap-1.5"><span className="w-4 h-1.5 rounded-full bg-emerald-500/25 border border-emerald-500/30"></span> IQR (middle 50%)</span>
                  <span className="inline-flex items-center gap-1.5"><Trophy className="w-3 h-3 text-emerald-400" /> Best price</span>
                  <span className="inline-flex items-center gap-1.5"><Skull className="w-3 h-3 text-red-400" /> Worst price</span>
                </div>
              </div>
            </Reveal>
          )}

          {/* Detail table */}
          {items.length > 0 && (
            <Reveal delay={0.2} className="mt-8">
              <div className="flex items-center justify-between mb-3 flex-wrap gap-2">
                <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500">
                  Side-by-side detail
                </div>
                {compare.count > 0 && (
                  <div className="flex items-center gap-2 ml-auto">
                    <button
                      onClick={() => {
                        navigator.clipboard.writeText(window.location.href);
                        toast.success("Compare link copied");
                      }}
                      data-testid="compare-copy-link"
                      className="inline-flex items-center gap-1.5 border border-white/10 hover:border-emerald-500/40 hover:text-emerald-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
                    >
                      <Copy className="w-3 h-3" /> Copy link
                    </button>
                    <AlertDialog>
                      <AlertDialogTrigger asChild>
                        <button
                          data-testid="compare-clear"
                        className="inline-flex items-center gap-1.5 border border-white/10 hover:border-red-500/40 hover:text-red-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
                      >
                        <X className="w-3 h-3" /> Clear all
                      </button>
                    </AlertDialogTrigger>
                    <AlertDialogContent className="bg-bg-base border-white/10 text-white">
                      <AlertDialogHeader>
                        <AlertDialogTitle>Clear all items?</AlertDialogTitle>
                        <AlertDialogDescription className="text-zinc-400">
                          This will remove all {compare.count} items from your compare list.
                        </AlertDialogDescription>
                      </AlertDialogHeader>
                      <AlertDialogFooter>
                        <AlertDialogCancel className="border-white/10 text-zinc-300 hover:bg-white/5">Cancel</AlertDialogCancel>
                        <AlertDialogAction
                          onClick={() => compare.clear()}
                          className="bg-red-500 hover:bg-red-400 text-black font-bold"
                        >
                          Clear all
                        </AlertDialogAction>
                      </AlertDialogFooter>
                    </AlertDialogContent>
                  </AlertDialog>
                  </div>
                )}
              </div>
              <div className="border border-white/10 rounded-2xl overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="bg-white/[0.02] border-b border-white/10 text-left">
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">Item</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden sm:table-cell">Category</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 text-right">Median</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 text-right hidden md:table-cell">IQR</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden md:table-cell">Conf.</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden lg:table-cell">Trend</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden lg:table-cell">Last seen</th>
                      <th className="px-4 py-3 w-12"></th>
                    </tr>
                  </thead>
                  <tbody>
                    {items.map((r) => {
                      const T = TREND[r.trend] || TREND.stable;
                      const conf = CONF[r.confidence] || CONF.unreliable;
                      const isBest = best && r.key === best.key && items.length > 1;
                      return (
                        <tr
                          key={r.key}
                          data-testid={`compare-row-${r.key}`}
                          onClick={() => openItem(searchParams, setSearchParams, r.key)}
                          onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); openItem(searchParams, setSearchParams, r.key); } }}
                          tabIndex={0}
                          role="link"
                          className="border-b border-white/5 last:border-0 hover:bg-white/[0.03] transition-colors cursor-pointer group"
                        >
                          <td className="px-4 py-4">
                            <div className="font-heading font-bold text-white group-hover:text-emerald-400 transition-colors flex items-center gap-2">
                              {isBest && <Trophy className="w-3.5 h-3.5 text-emerald-400 shrink-0" />}
                              <ItemName name={r.name} tier={r.tier} modifiers={r.modifiers} />
                            </div>
                          </td>
                          <td className="px-4 py-4 hidden sm:table-cell">
                            <span className="font-mono text-[10px] uppercase tracking-wider text-zinc-500">{r.category}</span>
                          </td>
                          <td className="px-4 py-4 text-right">
                            <span className="font-mono tabular text-white font-bold">{r.median > 0 ? fmt(r.median) : "—"}</span>
                          </td>
                          <td className="px-4 py-4 text-right hidden md:table-cell">
                            <span className="font-mono tabular text-zinc-400 text-xs">
                              {fmt(r.iqrLow)}–{fmt(r.iqrHigh)}
                            </span>
                          </td>
                          <td className="px-4 py-4 hidden md:table-cell">
                            <span className={`inline-flex items-center gap-1.5 font-mono text-xs ${conf.color}`}>
                              <span className={`inline-block w-1.5 h-1.5 rounded-full ${conf.dot}`}></span> {r.confidence}
                            </span>
                          </td>
                          <td className="px-4 py-4 hidden lg:table-cell">
                            <div className="inline-flex items-center gap-1.5">
                              <T.Icon className={`w-4 h-4 ${T.color}`} />
                              <span className="font-mono text-[10px] uppercase tracking-wider text-zinc-500">{r.trend}</span>
                            </div>
                          </td>
                          <td className="px-4 py-4 hidden lg:table-cell">
                            <span className="font-mono text-[10px] text-zinc-500">{fmtTime(r.lastSeenMs)}</span>
                          </td>
                          <td className="px-4 py-4 text-right">
                            <button
                              onClick={(e) => { e.stopPropagation(); compare.toggle(r.key); }}
                              data-testid={`compare-remove-${r.key}`}
                              aria-label="Remove from compare"
                              className="p-1 text-zinc-500 hover:text-red-400 transition-colors"
                            >
                              <X className="w-4 h-4" />
                            </button>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </Reveal>
          )}

          {items.length > 0 && items.length < 2 && (
            <div data-testid="compare-hint" className="mt-6 text-center text-zinc-500 text-xs font-mono uppercase tracking-wider">
              <AlertTriangle className="w-3.5 h-3.5 inline-block mr-1.5" />
              Add at least one more item to see the comparison chart.
            </div>
          )}
        </div>
      </main>
      <Footer />
      <BackToTop />
    </div>
  );
}
